// Берём объект параметров, который ты сформировала раньше
const q = $json.rssQuery || {};

// Функция сериализации в query-string
function toQuery(obj) {
  const parts = [];
  for (const [k, v] of Object.entries(obj)) {
    if (Array.isArray(v)) {
      for (const x of v) {
        parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(x)));
      }
    } else if (v !== undefined && v !== null) {
      parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
    }
  }
  return parts.join('&');
}

const query = toQuery(q);

return {
  json: {
    ...$json,
    fullUrl: `${$json.rssUrl}?${query}`, // готовый корректный URL
  },
};

// helpers
const asArray = v => Array.isArray(v) ? v : (v ? [v] : []);
const getText = v => {
  if (v == null) return '';
  if (Array.isArray(v)) return getText(v[0]);
  if (typeof v === 'object') {
    if ('text' in v) return getText(v.text);
    if ('_text' in v) return getText(v._text);
  }
  return String(v).trim();
};
const stripNs = obj => {
  if (!obj || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(stripNs);
  const out = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k.replace(/^ns\d+:/, '')] = stripNs(v);
  }
  return out;
};

// берём исходные items ИМЕННО из Parse RSS XML1
const srcItems = $items('Распарс документа');
const out = [];

for (const item of srcItems) {
  const json = item.json;

  // добавили EZT2020
  const rootRaw =
    json['ns7:epNotificationEOK2020'] ||
    json['ns7:epNotificationEF2020']  ||
    json['ns7:epNotificationEZK2020'] ||
    json['ns7:epNotificationEZT2020'];

  if (!rootRaw) continue;

  const root = stripNs(rootRaw);
  const regNumber = getText(root.commonInfo && root.commonInfo.purchaseNumber);

  const purchaseObjects =
    root.notificationInfo &&
    root.notificationInfo.purchaseObjectsInfo &&
    root.notificationInfo.purchaseObjectsInfo.notDrugPurchaseObjectsInfo;

  const positions = asArray(purchaseObjects && purchaseObjects.purchaseObject);

  if (!positions.length) {
    out.push({ json: { object_number: regNumber, note: 'no purchaseObject in XML' } });
    continue;
  }

  positions.forEach((po, index) => {
    const ktru = po.KTRU || {};
    const okei = po.OKEI || {};
    const qty  = po.quantity || {};
    const restrictions = po.restrictionsInfo || {};

    out.push({
      json: {
        object_number: regNumber,
        positionIndex: index,

        item_name: getText(ktru.name) || getText(po.name),
        price_for_one: getText(po.price),
        total_sum: getText(po.sum),
        item_type: getText(po.type),
        volume_specifying_method: getText(po.volumeSpecifyingMethod),

        okei_code: getText(okei.code),
        okei_name: getText(okei.name),
        okei_national_code: getText(okei.nationalCode),
        quantity_value: getText(qty.value),

        okpd2_code: getText((ktru.OKPD2 && ktru.OKPD2.OKPDCode) || (po.OKPD2 && po.OKPD2.OKPDCode)),
        okpd2_name: getText((ktru.OKPD2 && ktru.OKPD2.OKPDName) || (po.OKPD2 && po.OKPD2.OKPDName)),

        characteristics_detailed_json: ktru.characteristics || null,

        is_prohibition_foreign:
          getText(restrictions.isProhibitionForeignPurchaseObjects) === 'true',
        is_impossibility_prohibition:
          getText(restrictions.isImposibilityProhibition) === 'true',
        impossibility_reason:
          getText(restrictions.reasonImposibilityProhibition) || null,
        restriction_reasons_json: restrictions || null,
      },
    });
  });
}

return out;

// helpers
const asArray = v => Array.isArray(v) ? v : (v ? [v] : []);
const getText = v => {
  if (v == null) return '';
  if (Array.isArray(v)) return getText(v[0]);
  if (typeof v === 'object') {
    if ('text' in v) return getText(v.text);
    if ('_text' in v) return getText(v._text);
  }
  return String(v).trim();
};
const getIn = (o, path) =>
  path.reduce((a, k) => (a && a[k] !== undefined ? a[k] : undefined), o);

function stripNs(obj) {
  if (obj == null) return obj;
  if (Array.isArray(obj)) return obj.map(stripNs);
  if (typeof obj !== 'object') return obj;
  const out = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k.replace(/^ns\d+:/, '')] = stripNs(v);
  }
  return out;
}

// берём XML именно из Parse RSS XML1
const sources = $items('Распарс документа');
const out = [];

for (const src of sources) {
  const j = src.json;

  // поддерживаем EOK, EF, EZK, EZT
  const root =
    j['ns7:epNotificationEOK2020'] ||
    j['ns7:epNotificationEF2020']  ||
    j['ns7:epNotificationEZK2020'] ||
    j['ns7:epNotificationEZT2020'];

  if (!root) continue;

  const regNumber = getText(
    getIn(root, ['commonInfo', 'purchaseNumber'])
  );

  const attachments = asArray(
    getIn(root, ['attachmentsInfo', 'ns3:attachmentInfo']) || []
  );

  attachments.forEach((a, idx) => {
    const publishedContentId = getText(a['ns3:publishedContentId']);
    const fileName           = getText(a['ns3:fileName']);
    const fileSize           = getText(a['ns3:fileSize']);
    const docDescription     = getText(a['ns3:docDescription']);
    const docDate            = getText(a['ns3:docDate']);
    const url                = getText(a['ns3:url']);

    const kindRaw     = a['ns3:docKindInfo'] ?? {};
    const kind        = stripNs(kindRaw);
    const docKindCode = getText(kind.code);
    const docKindName = getText(kind.name);

    out.push({
      json: {
        object_number: regNumber,
        doc_index: idx,

        published_content_id: publishedContentId,
        file_name: fileName,
        file_size: fileSize,
        doc_description: docDescription,
        doc_date: docDate,
        url,
        doc_kind_code: docKindCode,
        doc_kind_name: docKindName,
      },
    });
  });
}

return out;

// Ключевые слова
const keywords = [
  $('When chat message received').first().json.chatInput
];

// Этапы (стадии)
const stages = {
  af: 'on', // Подача заявок
  ca: 'on', // Работа комиссии
  pa: 'on', // Финальная стадия (чтобы не терять тендеры, которые уже ушли с подачи заявок)
};

// Законы
const laws = {
  fz44: 'on',
  fz223: 'on',
};

// DD.MM.YYYY
function formatDDMMYYYY(d) {
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${dd}.${mm}.${yyyy}`;
}

// Последние 30 дней
const today = new Date();
const startDate = new Date(today);
startDate.setDate(today.getDate() - 30);

const publishDateFrom = formatDDMMYYYY(startDate);
const publishDateTo = formatDDMMYYYY(today);

// Базовые параметры
const baseParams = {
  morphology: 'on',
  sortDirection: 'false',
  recordsPerPage: '_50',
  showLotsInfoHidden: 'false',
  sortBy: 'UPDATE_DATE',
  publishDateFrom,
  publishDateTo,
};

const pagesPerKeyword = 1;
const itemsToReturn = [];

for (const keyword of keywords) {
  for (let page = 1; page <= pagesPerKeyword; page += 1) {
    const query = {
      ...baseParams,
      ...stages,
      ...laws,
      searchString: keyword,
      pageNumber: page,
    };

    itemsToReturn.push({
      json: {
        keyword,
        pageNumber: page,
        rssQuery: query,
        rssUrl: 'https://zakupki.gov.ru/epz/order/extendedsearch/rss.html',
      },
    });
  }
}

return itemsToReturn;

// Берём JSON после узла XML->JSON
const root = $json;

// Находим канал и массив item
const channel = root?.rss?.channel ?? root?.channel ?? {};
let list = channel?.item;
if (!list) return [];                 // нет элементов — нечего отдавать
if (!Array.isArray(list)) list = [list];

// Универсальная нормализация текста из XML-структур
const getText = (value) => {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return getText(value[0]);
  if (typeof value === 'object') {
    if ('text' in value) return getText(value.text);
    if ('_text' in value) return getText(value._text);
  }
  return String(value).trim();
};

// Парсим <strong>Метка:</strong> Значение → { kv }
function parseDescriptionToKV(html) {
  const norm = String(html || '').replace(/<br\s*\/?>/gi, '<br>');
  const chunks = norm.split(/<strong>/i).slice(1);

  const kv = {};
  for (const chunk of chunks) {
    const [labelRaw, restRaw = ''] = chunk.split(/<\/strong>/i);
    const label = (labelRaw || '').replace(/[:：]\s*$/, '').trim();
    const value = String((restRaw.split(/<strong>|<br\s*\/?>/i)[0] || ''))
      .replace(/<\/?[^>]+>/g, '')           // remove tags
      .replace(/&nbsp;/g, ' ')
      .replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&')
      .trim();
    if (label && value) {
      // ключи в "читаемом" виде; Google Sheets отлично живёт с кириллицей
      kv[label] = value;
    }
  }
  return kv;
}

// Плоское представление: разворачиваем объект в "ключ -> строка"
function flattenToStrings(obj, prefix = '', out = {}) {
  if (obj === null || obj === undefined) return out;

  for (const [k, vRaw] of Object.entries(obj)) {
    const key = prefix ? `${prefix}.${k}` : k;
    const v = vRaw;

    if (v === null || v === undefined) {
      out[key] = '';
      continue;
    }

    if (Array.isArray(v)) {
      if (v.length === 1) {
        // частый случай XML: одиночные массивы
        flattenToStrings(v[0], key, out);
      } else {
        out[key] = v.map(x => {
          if (x === null || x === undefined) return '';
          if (typeof x === 'object') {
            // если это объект, берём «текстовую» часть или JSON
            if ('text' in x || '_text' in x) return getText(x);
            return JSON.stringify(x);
          }
          return String(x);
        }).join('; ');
      }
      continue;
    }

    if (typeof v === 'object') {
      // если это XML-объект с текстом — берём текст
      if ('text' in v || '_text' in v) {
        out[key] = getText(v);
      } else {
        flattenToStrings(v, key, out);
      }
      continue;
    }

    out[key] = String(v);
  }

  return out;
}

// Строим «плоские» записи по каждому item
const rows = list.map((it) => {
  // Базовые поля как строки
  const title = getText(it.title);
  const linkRaw = getText(it.link);
  const link = linkRaw && /^https?:\/\//i.test(linkRaw)
    ? linkRaw
    : (linkRaw ? `https://zakupki.gov.ru${linkRaw}` : '');
  const author = getText(it.author);
  const pubDate = getText(it.pubDate);

  // 44/223 — по ссылке
  const law = link.includes('/223/') ? '223' : '44';

  // Парсим описание в объект «метка: значение»
  const descHtml = getText(it.description);
  const description_kv = parseDescriptionToKV(descHtml);

  // Собираем объект для разворачивания
  const base = {
    title,
    link,
    author,
    pubDate,
    law,
    // добавим исходный регномер, если есть в ссылке/титле
    regNumber:
      (link.match(/regNumber=(\d+)/)?.[1]) ||
      (title.match(/№\s*(\d{8,})/)?.[1]) ||
      (title.match(/(\d{8,})/)?.[1]) ||
      '',
    // кладём распарсенные пары в отдельную ветку
    description_kv,
  };

  // ПРИМЕЧАНИЕ: само поле description_kv мы хотим развернуть в колонки,
  // поэтому ниже «плоско» перенесём его: description_kv.Этап закупки → "Подача заявок".
  const flatBase = flattenToStrings(base);

  // Явно разворачиваем пары description_kv в верхний уровень с префиксом
  for (const [k, v] of Object.entries(description_kv)) {
    flatBase[`description_kv.${k}`] = String(v);
  }

  // Если хочется убрать «сырые» ветки (например, не выводить целиком JSON description_kv),
  // можно удалить:
  delete flatBase['description_kv'];

  return { json: flatBase };
});

// Возвращаем массив записей, каждая — плоский объект из строк → готово для Google Sheets
return rows;

const html = $json.data || '';

// Ищем ссылку вида .../print-form/show.html?pfid=NNN
const match = html.match(/https:\/\/zakupki\.gov\.ru\/223\/purchase\/public\/print-form\/show\.html\?pfid=\d+/i);

// Ищем значение из тега div.common-text__value по указанному пути
const valueMatch = html.match(/<div[^>]*class=["']common-text__value["'][^>]*>([\s\S]*?)<\/div>/i);
const value = valueMatch ? valueMatch[1].trim() : null;

// Возвращаем один айтем (объект), даже если не нашли
return {
  json: {
    url: match ? match[0] : null,
    value: value
  }
};

const html = $json.data;

// 1) достаём содержимое div#tabs-2
const m = html.match(/<div[^>]*id=["']tabs-2["'][^>]*>([\s\S]*?)<\/div>/i);
if (!m) throw new Error('div#tabs-2 not found');

let s = m[1];

// 2) иногда внутри есть теги/брейки — уберём их
s = s
  .replace(/<(script|style)[^>]*>[\s\S]*?<\/\1>/gi, '')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/?[^>]+>/g, ''); // убираем остальные HTML-теги

// 3) декодируем сущности: числовые (dec/hex) и именованные
const decodeEntities = (t) => t
  // hex: &#xNN;
  .replace(/&#x([0-9a-fA-F]+);/g, (_, h) => String.fromCharCode(parseInt(h, 16)))
  // dec: &#NNN;
  .replace(/&#(\d+);/g, (_, d) => String.fromCharCode(parseInt(d, 10)))
  // именованные
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;|&#34;|&#x22;/g, '"')
  .replace(/&apos;|&#39;|&#x27;/g, "'")
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&'); // важно — в конце

s = decodeEntities(s).trim();

// 4) на всякий случай уберём BOM и мусор до XML-декларации
s = s.replace(/^\uFEFF/, '');
const p = s.indexOf('<?xml');
if (p > 0) s = s.slice(p);

return { 
  json: { 
    xml: s 
  } 
};

const items = $input.all();

return items.map(item => {
  const j = item.json;

  // 1. Ищем любой из возможных корней (Envelope)
  const rootKey = [
    'ns2:purchaseNoticeZKESMBO',
    'ns2:purchaseNoticeKESMBO',
    'ns2:purchaseNoticeZPESMBO',
    'ns2:purchaseNoticeAESMBO',
    'ns2:purchaseNoticeEP',
    'ns2:purchaseNoticeAE',
    'ns2:purchaseNotice',
    'ns2:purchaseNoticeZK', // бывает и такой
    'ns2:protocol'          // на случай протоколов
  ].find(k => j[k]);

  if (!rootKey) {
    return { json: { ...j, _error: 'Unsupported 223-FZ root' } };
  }

  // Берем сам объект корня
  const root = j[rootKey];

  // 2. Лезем внутрь до уровня item
  const body = root['ns2:body'];
  const itemNode = body && body['ns2:item'] ? body['ns2:item'] : null;

  let regNumber = null;

  // 3. САМОЕ ВАЖНОЕ: нормализуем "плавающий" ключ данных внутри item
  if (itemNode) {
    // Ищем ключ, который заканчивается на 'Data' (например ns2:purchaseNoticeZKESMBOData)
    const dynamicDataKey = Object.keys(itemNode).find(k => k.endsWith('Data'));

    if (dynamicDataKey) {
      // Создаем СТАНДАРТНЫЙ ключ '_unifiedData' прямо внутри объекта itemNode.
      // Теперь неважно, как назывались данные (ZKESMBOData или AESMBOData),
      // они всегда будут доступны и по старому имени, и по 'itemNode._unifiedData'.
      itemNode['_unifiedData'] = itemNode[dynamicDataKey];

      // Заодно вытащим номер для верхнего уровня
      regNumber = itemNode[dynamicDataKey]['ns2:registrationNumber'];
    } else {
      // Если вдруг Data-ключа нет, считаем, что данные лежат в самом item (fallback)
      itemNode['_unifiedData'] = itemNode; 
    }
  }

  const unified = {
    ...j,
    _root: root, // Это тот же объект, но внутри него теперь есть _unifiedData
    object_number: regNumber || null,
    zakon: '223fz',
  };

  return { json: unified };
});

// helpers
const asArray = v => Array.isArray(v) ? v : (v ? [v] : []);
const getText = v => {
  if (v == null) return '';
  if (Array.isArray(v)) return getText(v[0]);
  if (typeof v === 'object') {
    if ('text' in v) return getText(v.text);
    if ('_text' in v) return getText(v._text);
  }
  return String(v).trim();
};

const stripNs = obj => {
  if (!obj || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(stripNs);
  const out = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k.replace(/^[a-zA-Z0-9]+:/, '')] = stripNs(v);
  }
  return out;
};

// Берём данные СТРОГО из ноды нормализации
const srcItems = $items('Нормализуем строки');
const out = [];

for (const item of srcItems) {
  const json = item.json;

  // Достаем _unifiedData
  const itemNode = json._root?.['ns2:body']?.['ns2:item'];
  const unifiedDataRaw = itemNode?.['_unifiedData'];

  if (!unifiedDataRaw) continue;

  const data = stripNs(unifiedDataRaw);
  const regNumber = json.object_number || getText(data.registrationNumber);

  // Путь к документам в 223-ФЗ: attachments -> document
  const docs = asArray(data.attachments && data.attachments.document);

  if (!docs.length) {
     out.push({ json: { object_number: regNumber, note: 'no attachments in 223-FZ XML' } });
     continue;
  }

  docs.forEach((doc, idx) => {
    // В 223-ФЗ поля называются немного иначе, чем в 44-ФЗ
    // guid - это ID документа
    // fileName - имя файла
    // description - описание
    // url - ссылка

    out.push({
      json: {
        object_number: regNumber,
        doc_index: idx,

        published_content_id: getText(doc.guid),
        file_name: getText(doc.fileName),

        // Размер файла в метаданных 223-ФЗ часто отсутствует, оставляем null или 0
        file_size: null, 

        doc_description: getText(doc.description) || getText(doc.name),

        // Дата документа часто совпадает с датой создания записи
        doc_date: getText(doc.createDateTime) || getText(data.createDateTime),

        url: getText(doc.url),

        // В 223-ФЗ нет строгих кодов видов документов (как docKind в 44-ФЗ)
        doc_kind_code: null,
        doc_kind_name: null,
      },
    });
  });
}

return out;

// helpers
const asArray = v => Array.isArray(v) ? v : (v ? [v] : []);
const getText = v => {
  if (v == null) return '';
  if (Array.isArray(v)) return getText(v[0]);
  if (typeof v === 'object') {
    if ('text' in v) return getText(v.text);
    if ('_text' in v) return getText(v._text);
  }
  return String(v).trim();
};

const stripNs = obj => {
  if (!obj || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(stripNs);
  const out = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k.replace(/^[a-zA-Z0-9]+:/, '')] = stripNs(v);
  }
  return out;
};

const srcItems = $items('Нормализуем строки');
const out = [];

for (const item of srcItems) {
  const json = item.json;

  const itemNode = json._root?.['ns2:body']?.['ns2:item'];
  const unifiedDataRaw = itemNode?.['_unifiedData'];

  if (!unifiedDataRaw) continue;

  const data = stripNs(unifiedDataRaw);
  const regNumber = json.object_number || getText(data.registrationNumber);

  const lots = asArray(data.lots && data.lots.lot);

  if (!lots.length) {
     out.push({ json: { object_number: regNumber, note: 'no lots in 223-FZ XML' } });
     continue;
  }

  let globalItemIndex = 0;

  lots.forEach((lot, lotIdx) => {
    // ВАЖНО: В 223-ФЗ данные лота могут лежать в lotData!
    // Ищем lotItems либо прямо в lot, либо в lot.lotData
    const lotSource = lot.lotData || lot; 

    const lotItems = asArray(lotSource.lotItems && lotSource.lotItems.lotItem);

    // Если lotItems нет, берем сам лот как товар
    const itemsToProcess = lotItems.length ? lotItems : [lotSource];

    itemsToProcess.forEach((pos) => {
        const okei = pos.okei || {};
        const qtyVal = getText(pos.qty) || getText(pos.quantity); 
        const okpd2 = pos.okpd2 || {};

        out.push({
          json: {
            object_number: regNumber,
            positionIndex: globalItemIndex++,
            lot_index: lotIdx + 1,

            // Название берем из pos.subject, pos.name или из lotData.subject
            item_name: getText(pos.name) || getText(pos.subject) || getText(lotSource.subject),

            price_for_one: getText(pos.price), 
            total_sum: getText(pos.sum) || getText(pos.amount) || getText(lotSource.initialSum),

            okei_code: getText(okei.code),
            okei_name: getText(okei.name),
            okei_national_code: getText(okei.nationalCode),

            quantity_value: qtyVal,

            okpd2_code: getText(okpd2.code),
            okpd2_name: getText(okpd2.name),

            characteristics_detailed_json: null, 
          },
        });
    });
  });
}

return out;

const items = $input.all();

return items.map(item => {
  const j = item.json;

  // ищем реальный корень среди всех вариантов
  const root =
    j['ns7:epNotificationEOK2020'] ||
    j['ns7:epNotificationEF2020']  ||
